import { Layout, Dropdown, Avatar, Button, Divider } from "antd";
import {
  MdMenu,
  MdOutlineLogout,
  MdOutlineAccountCircle,
} from "react-icons/md";
import { FaChevronDown } from "react-icons/fa";

import { useDispatch, useSelector } from "react-redux";
import { getColor, getFirstCharacter } from "../constants/avata.constant";
import { useNavigate } from "react-router-dom";
import { logout } from "../stores/slices/auth.slice";
import NotificationDropdown from "../pages/notifications/NotificationDropdown";
import { RiLockPasswordLine } from "react-icons/ri";
import { useTheme } from "../configs/useTheme";

const { Header } = Layout;

const AppHeader = () => {
  const { updateConfig } = useTheme();
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auths);

  const toggleSidebar = () => {
    const html = document.documentElement;

    html.classList.toggle("sidebar-enable");
    const isCondensed = html.getAttribute("data-sidenav-size") === "condensed";
    const newSize = isCondensed ? "default" : "condensed";

    html.setAttribute("data-sidenav-size", newSize);
    updateConfig("sidenav", { size: newSize });
  };

  // const toggleTheme = () => {
  //   updateConfig("theme", config.theme === "light" ? "dark" : "light");
  // };

  const userMenu = (
    <div className="dropdown-menu dropdown-menu-end show">
      {/* <div className="dropdown-header bg-primary mt-n3 rounded-top-2">
        <h6 className="text-overflow text-white m-0">Welcome !</h6>
      </div> */}
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/profile");
        }}
      >
        <MdOutlineAccountCircle className="me-2" /> <span>Profile</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/change-password");
        }}
      >
        <RiLockPasswordLine className="me-2" /> <span>Đổi mật khẩu</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item"
        onClick={(e) => {
          e.preventDefault();
          navigate("/login");
          dispatch(logout());
        }}
      >
        <MdOutlineLogout className="me-2" /> <span>Đăng xuất</span>
      </a>
    </div>
  );

  return (
    <Header className="app-topbar bg-white shadow-sm px-3">
      <div className="page-container topbar-menu">
        <div className="d-flex align-items-center gap-2">
          {/* Brand Logo */}
          <a href="/" className="logo">
            <span className="logo-light">
              <span className="logo-lg">
                <img src="/assets/images/logo-light.png" alt="logo" />
              </span>
              <span className="logo-sm">
                <img src="/assets/images/logo-sm-light.png" alt="small logo" />
              </span>
            </span>
            <span className="logo-dark">
              <span className="logo-lg">
                <img src="/assets/images/logo-dark.png" alt="dark logo" />
              </span>
              <span className="logo-sm">
                <img src="/assets/images/logo-sm.png" alt="small logo" />
              </span>
            </span>
          </a>

          <Button
            type="text"
            className="sidenav-toggle-button px-2"
            icon={<MdMenu className="font-24" />}
            onClick={toggleSidebar}
          />

          {/* <Button
            type="text"
            className="topnav-toggle-button px-2"
            icon={<MdMenu className="font-22" />}
            onClick={toggleSidebar}
          /> */}
        </div>

        <div className="d-flex align-items-center gap-2">
          {/* <div className="topbar-item d-none d-sm-flex">
            <Button
              type="text"
              className="topbar-link"
              id="light-dark-mode"
              icon={<FaMoon className="font-22" />}
              onClick={toggleTheme}
            />
          </div> */}

          {/* Notifications */}
          <div className="topbar-item">
            <NotificationDropdown />
          </div>

          {/* Emails */}
          {/* <div className="topbar-item">
            <Button
              type="text"
              className="topbar-link position-relative"
              icon={<MdOutlineEmail className="font-22" />}
            />
          </div> */}

          {user && (
            <div className="topbar-item nav-user">
              <Dropdown
                popupRender={() => userMenu}
                placement="bottomRight"
                trigger={["click"]}
              >
                <a
                  className="topbar-link dropdown-toggle drop-arrow-none px-2"
                  onClick={(e) => e.preventDefault()}
                >
                  {user.user?.image ? (
                    <Avatar src={user.user?.image} />
                  ) : (
                    <Avatar
                      style={{
                        backgroundColor: getColor(
                          `${user.user?.first_name} ${user.user?.last_name}`
                        ),
                        color: "#fff",
                      }}
                    >
                      {getFirstCharacter(
                        `${user.user?.first_name} ${user.user?.last_name}`
                      )}
                    </Avatar>
                  )}

                  <span className="d-lg-flex flex-column gap-1 d-none">
                    <h6 className="my-0 ms-2">
                      {user.user?.first_name} {user.user?.last_name}
                    </h6>
                  </span>
                  <FaChevronDown className="d-none d-lg-block align-middle ms-2" />
                </a>
              </Dropdown>
            </div>
          )}

          {/* Settings */}
          {/* <div className="topbar-item d-none d-sm-flex">
            <Button
              type="text"
              className="topbar-link"
              icon={<MdOutlineSettings className="font-22" />}
            />
          </div> */}
        </div>
      </div>
    </Header>
  );
};

export default AppHeader;

import React from "react";
import { Select } from "antd";

const DashboardHeader = () => {
  return (
    <>
      {/* DASHBOARD CONTENT HEADER — title + filters + export on ONE row */}
      <div className="dashboard-content-header">
        <h1 className="dashboard-content-title">Dashboard</h1>

        <div className="dashboard-content-controls">
          <Select
            defaultValue="hanoi"
            style={{ width: 160 }}
            size="middle"
            options={[
              { value: "hanoi", label: "📍 Hà Nội" },
              { value: "hcm", label: "Hồ Chí Minh" },
              { value: "danang", label: "Đà Nẵng" },
            ]}
          />
          <Select
            defaultValue="t6t8"
            style={{ width: 150 }}
            size="middle"
            options={[
              { value: "t6t8", label: "T6 - T8/2026" },
              { value: "t1t3", label: "T1 - T3/2026" },
              { value: "t4t6", label: "T4 - T6/2026" },
              { value: "t9t12", label: "T9 - T12/2026" },
            ]}
          />
          <button className="export-btn" title="Xuất dữ liệu">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="18"
              height="18"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
              <polyline points="7 10 12 15 17 10" />
              <line x1="12" y1="15" x2="12" y2="3" />
            </svg>
          </button>
        </div>
      </div>
    </>
  );
};

export default DashboardHeader;

