  padding-bottom: 24px;
  margin-bottom: 0;
  /* no extra background/border — just layout */
}

.dashboard-content-title {
  font-size: 26px;
  font-weight: 700;
  color: #1F2937;
  margin: 0;
  letter-spacing: -0.5px;
  white-space: nowrap;
  flex-shrink: 0;
}

.dashboard-content-controls {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

/* Export icon button */
.export-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  background: #EFF6FF;
  border: 1px solid #DBEAFE;
  color: #1D4ED8;
  cursor: pointer;
  font-size: 18px;
  transition: all 0.15s ease;
  padding: 0;
}

