import React, { useRef } from "react";
import { Badge, Button, Dropdown } from "antd";
import { MdOutlineNotificationsNone } from "react-icons/md";
import { motion as Motion, AnimatePresence } from "framer-motion";
import dayjs from "dayjs";
import { CheckOutlined, BellOutlined } from "@ant-design/icons";
import { useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import useNotifications from "../../hooks/useNotifications";

export default function NotificationDropdown() {
  const navigate = useNavigate();
  const scrollRef = useRef(null);

  const { notifications, unreadCount, loading, hasMore, loadMore, markAsRead } =
    useNotifications();

  const { user } = useSelector((state) => state.auths);

  const handleLoadMore = async () => {
    if (!hasMore || loading) return;

    const div = scrollRef.current;
    const prevHeight = div.scrollHeight;

    await loadMore();

    requestAnimationFrame(() => {
      div.scrollTop = div.scrollHeight - prevHeight + div.scrollTop;
    });
  };

  const renderNotifications = () => {
    if (loading)
      return (
        <div className="text-center py-3">
          <div className="spinner-border spinner-border-sm" />
        </div>
      );

    if (!notifications.length)
      return (
        <div className="text-center py-3 text-muted">
          <BellOutlined className="fs-4 opacity-75" />
          <div>Không có thông báo</div>
        </div>
      );

    return (
      <AnimatePresence>
        {notifications.map((n) => {
          const isRead = n.status === "read";

          return (
            <Motion.div
              key={n._id}
              initial={{ opacity: 0, y: -5 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 5 }}
              transition={{ duration: 0.2 }}
              onClick={() => {
                !isRead && markAsRead(n.notify_id, user?.user?.id);
              }}
              className={`p-2 rounded-3 mb-2 notif-item d-flex align-item-center ${
                isRead ? "notif-read" : "notif-unread"
              }`}
              style={{ cursor: "pointer" }}
            >
              <div className="flex-grow-1">
                <div className={isRead ? "text-muted" : "fw-bold text-dark"}>
                  {`${n.content?.title || "Thông báo"} - ${
                    n.content?.content || ""
                  }`}
                </div>
                <small className="text-muted">
                  {dayjs(n.created_at).format("DD/MM/YYYY HH:mm")}
                </small>
              </div>
              {!isRead && (
                <div>
                  <span
                    className="badge bg-primary shadow-sm"
                    style={{
                      width: 10,
                      height: 10,
                      display: "inline-block",
                      borderRadius: "50%",
                      padding: 0,
                    }}
                  />
                </div>
              )}
            </Motion.div>
          );
        })}
      </AnimatePresence>
    );
  };

  const dropdownContent = (
    <div
      className="bg-light-subtle"
      style={{ width: 380 }}
      onClick={(e) => e.stopPropagation()}
    >
      <div className="d-flex justify-content-between border-bottom px-3 py-2 bg-light">
        <span className="fw-semibold small">Thông báo</span>

        {unreadCount > 0 && (
          <Button
            size="small"
            type="link"
            className="p-0"
            onClick={() =>
              notifications.forEach((n) =>
                markAsRead(n.notify_id, user?.user?.id)
              )
            }
          >
            <CheckOutlined /> Đánh dấu đã đọc
          </Button>
        )}
      </div>

      <div
        ref={scrollRef}
        className="px-3 py-2"
        style={{ maxHeight: 330, overflowY: "auto" }}
      >
        {renderNotifications()}
      </div>

      <div className="border-top px-3 py-2 d-flex justify-content-between bg-light">
        {hasMore ? (
          <Button type="link" className="p-0 small" onClick={handleLoadMore}>
            Xem thêm
          </Button>
        ) : (
          <span />
        )}

        <Button
          type="link"
          className="p-0 small"
          onClick={() => navigate("/logs")}
        >
          Xem tất cả
        </Button>
      </div>
    </div>
  );

  return (
    <Dropdown
      popupRender={() => dropdownContent}
      placement="bottomRight"
      trigger={["click"]}
    >
      <Button
        type="text"
        icon={
          <Badge count={unreadCount} size="small" offset={[5, -3]}>
            <MdOutlineNotificationsNone className="fs-4 text-secondary" />
          </Badge>
        }
      />
    </Dropdown>
  );
}

