.page-content {
  margin-top: 0 !important;
  padding-top: 0 !important;
}

/* ============================================
   DASHBOARD — no duplicate header
   ============================================ */
.dashboard-content-header {
  display: none !important; /* hidden — topbar handles everything */
}

