import React from "react";
import KPICards from "../components/KPICards";
import GrowthChart from "../components/GrowthChart";
import CostDonutChart from "../components/CostDonutChart";
import CourseList from "../components/CourseList";
import StudentTeacherChart from "../components/StudentTeacherChart";

const ChartsDashboard = () => {
  return (
    <div
      style={{
        padding: "24px 28px",
        display: "flex",
        flexDirection: "column",
        gap: 0,
        minHeight: "calc(100vh - 60px)",
      }}
    >
      <KPICards />
      <GrowthChart />
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(360px, 1fr))",
          gap: 20,
          marginTop: 0,
        }}
      >
        <CostDonutChart />
        <CourseList />
      </div>
      <StudentTeacherChart />
    </div>
  );
};

export default ChartsDashboard;

import { Layout, Dropdown, Avatar, Button, Divider } from "antd";
import {
  MdMenu,
  MdOutlineLogout,
  MdOutlineAccountCircle,
} from "react-icons/md";
import { FaChevronDown } from "react-icons/fa";

import { useDispatch, useSelector } from "react-redux";
import { getColor, getFirstCharacter } from "../constants/avata.constant";
import { useNavigate } from "react-router-dom";
import { logout } from "../stores/slices/auth.slice";
import NotificationDropdown from "../pages/notifications/NotificationDropdown";
import { RiLockPasswordLine } from "react-icons/ri";
import { useTheme } from "../configs/useTheme";

const { Header } = Layout;

// Bell Icon SVG component
const BellIcon = () => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width="20"
    height="20"
    viewBox="0 0 24 24"
    fill="none"
    stroke="#6B7280"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
    style={{ cursor: "pointer" }}
  >
    <path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9" />
    <path d="M10.3 21a1.94 1.94 0 0 0 3.4 0" />
  </svg>
);

const AppHeader = () => {
  const { updateConfig } = useTheme();
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auths);

  const toggleSidebar = () => {
    const html = document.documentElement;

    html.classList.toggle("sidebar-enable");
    const isCondensed = html.getAttribute("data-sidenav-size") === "condensed";
    const newSize = isCondensed ? "default" : "condensed";

    html.setAttribute("data-sidenav-size", newSize);
    updateConfig("sidenav", { size: newSize });
  };

  // const toggleTheme = () => {
  //   updateConfig("theme", config.theme === "light" ? "dark" : "light");
  // };

  const userMenu = (
    <div className="dropdown-menu dropdown-menu-end show">
      {/* <div className="dropdown-header bg-primary mt-n3 rounded-top-2">
        <h6 className="text-overflow text-white m-0">Welcome !</h6>
      </div> */}
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/profile");
        }}
      >
        <MdOutlineAccountCircle className="me-2" /> <span>Profile</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/change-password");
        }}
      >
        <RiLockPasswordLine className="me-2" /> <span>Đổi mật khẩu</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item"
        onClick={(e) => {
          e.preventDefault();
          navigate("/login");
          dispatch(logout());
        }}
      >
        <MdOutlineLogout className="me-2" /> <span>Đăng xuất</span>
      </a>
    </div>
  );

  return (
    <Header className="app-topbar bg-white shadow-sm px-3">
      <div className="page-container topbar-menu">
        {/* Left: hamburger toggle */}
        <div className="d-flex align-items-center gap-2">
          <Button
            type="text"
            className="sidenav-toggle-button px-2"
            icon={<MdMenu className="font-24" />}
            onClick={toggleSidebar}
          />
        </div>

        {/* Center: pill search bar */}
        <div className="topbar-search-wrapper">
          <div className="topbar-search-pill">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="15"
              height="15"
              viewBox="0 0 24 24"
              fill="none"
              stroke="#9CA3AF"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <circle cx="11" cy="11" r="8" />
              <path d="m21 21-4.35-4.35" />
            </svg>
            <input
              type="text"
              placeholder="Tìm kiếm..."
              className="topbar-search-input"
            />
          </div>
        </div>

        {/* Right: bell + admin profile */}
        <div className="d-flex align-items-center gap-3">
          {/* Bell notification */}
          <div className="topbar-item">
            <NotificationDropdown />
          </div>

          {user && (
            <div className="topbar-item nav-user">
              <Dropdown
                popupRender={() => userMenu}
                placement="bottomRight"
                trigger={["click"]}
              >
                <a
                  className="topbar-link dropdown-toggle drop-arrow-none px-2"
                  onClick={(e) => e.preventDefault()}
                >
                  <span className="topbar-admin-name">Admin</span>
                  {user.user?.image ? (
                    <Avatar src={user.user?.image} className="topbar-avatar" />
                  ) : (
                    <Avatar
                      className="topbar-avatar"
                      style={{
                        backgroundColor: getColor(
                          `${user.user?.first_name} ${user.user?.last_name}`
                        ),
                        color: "#fff",
                      }}
                    >
                      {getFirstCharacter(
                        `${user.user?.first_name} ${user.user?.last_name}`
                      )}
                    </Avatar>
                  )}
                </a>
              </Dropdown>
            </div>
          )}
        </div>
      </div>
    </Header>
  );
};

export default AppHeader;
